SELECT seller_key as "id", business_name as "businessName", business_type as "businessType", contact_email as "contactEmail", rating as "rating", fulfillment_rate as "fulfillmentRate", total_products as "totalOrders", commission_rate as "commissionRate", seller_status as "stateId", tier as "tier", city as "city", state as "state", health_score as "healthScore", active_date as "createdAt" FROM hm_query.dim_seller
AND business_name LIKE CONCAT('%', #{businessName}, '%') AND contact_email LIKE CONCAT('%', #{contactEmail}, '%') AND business_type = #{businessType} AND seller_status = #{stateId} AND tier = #{tier} AND city LIKE CONCAT('%', #{city}, '%') AND state = #{state} AND (business_name LIKE CONCAT('%', #{q}, '%') OR contact_email LIKE CONCAT('%', #{q}, '%') OR store_name LIKE CONCAT('%', #{q}, '%'))
${orderby} ${pagination}

